SELECT segment_name
FROM vehicle_segments
WHERE capacity > 20;

SELECT DISTINCT segment_id
FROM vehicle_segments
ORDER BY segment_id;

SELECT segment_name, emissions_reduction
FROM vehicle_segments
ORDER BY emissions_reduction DESC;

SELECT segment_name, emissions_reduction
FROM vehicle_segments
WHERE segment_id = 0;

SELECT SUM(disbursal_amount) AS total_disbursed
FROM incentive_disbursals
WHERE status = 'completed';

SELECT eligibility_criteria
FROM incentives
WHERE incentive_id = 1;

SELECT segment_id, SUM(total_budget) AS total_segment_budget
FROM incentives
GROUP BY segment_id;
